toolCalls.args:
{"command": "cd /tmp/symbols && \
# Find the actual function symbols for each address
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  echo "=== $addr ==="
  aarch64-linux-gnu-nm -D --defined-only libmonosgen-2.0.so | sort | awk -v addr="$addr" '
    BEGIN{target=strtonum(addr)} 
    {cur=strtonum("0x"$1); if(cur<=target){name=$3; base=cur}} 
    END{printf "  %s+0x%x\n", name, target-base}'
done", "description": "Resolve all mono addresses to symbols"}

arguments.command:
cd /tmp/symbols && \
# Use dynamic symbol table with sizes to find proper enclosing function
aarch64-linux-gnu-readelf -W --dyn-syms libmonosgen-2.0.so | awk '
  $4 == "FUNC" && strtonum("0x"$2) > 0 {
    addr = strtonum("0x"$2)
    size = strtonum("0x"$3) + 0
    # Store symbol info
    symbols[NR] = addr " " size " " $8
  }
  END {
    split("0x222098 0x222234 0x19bac0 0x19bc14", targets, " ")
    for (t in targets) {
      target = strtonum(targets[t])
      best_name = "??"; best_offset = 0; best_match = 0
      for (s in symbols) {
        split(symbols[s], parts, " ")
        saddr = parts[1]+0; ssize = parts[2]+0; sname = parts[3]
        if (saddr <= target && (ssize == 0 || target < saddr + ssize)) {
          if (saddr > best_match) {
            best_match = saddr; best_name = sname; best_offset = target - saddr
          }
        }
      }
      printf "%s -> %s+0x%x\n", targets[t], best_name, best_offset
    }
  }' 2>/dev/null

