arguments.command:
cd /tmp/symbols && \
# Let's try a simpler approach with objdump -T which shows symbol sizes
aarch64-linux-gnu-objdump -T libmonosgen-2.0.so | awk '
  /\.text/ && $5+0 > 0 {
    addr = strtonum("0x"$1)
    size = strtonum("0x"$5)
    name = $NF
    syms[addr] = name " " size
  }
  END {
    n = asorti(syms, sorted_addrs, "@ind_num_asc")
    split("0x222098 0x222234 0x19bac0 0x19bc14", targets, " ")
    for (t in targets) {
      target = strtonum(targets[t])
      best = ""; best_addr = 0
      for (i = 1; i <= n; i++) {
        a = sorted_addrs[i]+0
        if (a <= target) { best = syms[sorted_addrs[i]]; best_addr = a }
        else break
      }
      split(best, parts, " ")
      printf "%s -> %s+0x%x\n", targets[t], parts[1], target - best_addr
    }
  }'

